const NAV_LINKS: NavLink[] = [
  { href: '/dashboard', label: 'Dashboard', icon: ICONS.dashboard },
  { href: '/medications', label: 'Medications', icon: ICONS.medications, roles: ['patient'] },
  { href: '/insights', label: 'Health Insights', icon: ICONS.insights },
  { href: '/timeline', label: 'Care Timeline', icon: ICONS.timeline },
  { href: '/check-in', label: 'Video Check-in', icon: ICONS.checkin, roles: ['patient'] },
  { href: '/ehr', label: 'EHR Records', icon: ICONS.ehr, roles: ['clinician', 'patient'] },
  { href: '/chat', label: 'Chat', icon: ICONS.chat },
  { href: '/clinician', label: 'Clinical View', icon: ICONS.clinician, roles: ['clinician'] },
  { href: '/agents', label: 'Agent Activity', icon: ICONS.agents, roles: ['clinician'] },
];

const ROLE_BADGE_VARIANT: Record<UserRole, 'success' | 'info' | 'warning'> = {
  patient: 'success',
  clinician: 'info',
  family: 'warning',
};

export function Nav() {
  const pathname = usePathname();
  const router = useRouter();
  const { userName, userRole } = useStore();
  const [mobileOpen, setMobileOpen] = useState(false);

  const filteredLinks = NAV_LINKS.filter((link) => !link.roles || link.roles.includes(userRole));
  const showPatientSelector = userRole === 'clinician' || userRole === 'family';

  async function handleSignOut() {
    await signOut(router);
  }

  const sidebarContent = (
    <>
      {/* Brand header with role indicator */}
      <div className="p-5 border-b" style={{ borderColor: 'var(--nav-border)' }}>
        <Link
          href="/dashboard"
          className="font-semibold text-lg tracking-tight"
          style={{ color: 'var(--nav-brand)' }}
          onClick={() => setMobileOpen(false)}
        >
          CAREHIVE
        </Link>
        <div className="flex items-center gap-2 mt-2">
          <Badge variant={ROLE_BADGE_VARIANT[userRole]} size="sm" dot>{ROLE_LABELS[userRole]}</Badge>
        </div>
      </div>

      {/* Patient selector for clinician/family */}
      {showPatientSelector && (
        <div className="px-3 pt-3">
          <p className="text-xs font-medium mb-1.5 px-1" style={{ color: 'var(--muted)' }}>
            {userRole === 'clinician' ? 'Viewing Patient' : 'Viewing Family Member'}
          </p>
          <PatientSelector />
        </div>
      )}

      <ul className="p-3 flex-1 space-y-0.5">
        {filteredLinks.map(({ href, label, icon }) => {
          const isActive = pathname === href;
          return (
            <li key={href}>
              <Link
                href={href}
                onClick={() => setMobileOpen(false)}
                className="flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors"
                style={{
                  background: isActive ? 'var(--nav-active-bg)' : 'transparent',
                  color: isActive ? 'var(--nav-active-text)' : 'var(--muted)',
                }}
              >
                {icon}
                {label}
              </Link>
            </li>
          );
        })}
      </ul>

      <div className="p-3 border-t space-y-0.5" style={{ borderColor: 'var(--nav-border)' }}>
        {userName && (
          <p className="px-3 py-1.5 text-xs truncate" style={{ color: 'var(--muted)' }} title={userName}>
            {userName}
          </p>
        )}
        <Link
          href="/profile"
          onClick={() => setMobileOpen(false)}
          className="flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors"
          style={{
            background: pathname === '/profile' ? 'var(--nav-active-bg)' : 'transparent',
            color: pathname === '/profile' ? 'var(--nav-active-text)' : 'var(--muted)',
          }}
        >
          {ICONS.profile}
          Profile
        </Link>
        <button
          type="button"
          onClick={handleSignOut}
          className="w-full flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors hover:opacity-80"
          style={{ color: 'var(--muted)' }}
        >
          {ICONS.signout}
          Sign out
        </button>
      </div>
    </>
  );

  return (
    <>
      {/* Mobile hamburger */}
      <button
        type="button"
        onClick={() => setMobileOpen(true)}
        className="md:hidden fixed top-4 left-4 z-50 p-2 rounded-lg border shadow-sm backdrop-blur"
        style={{
          background: 'var(--nav-bg)',
          borderColor: 'var(--nav-border)',
        }}
        aria-label="Open menu"
      >
        <svg className="w-5 h-5" style={{ color: 'var(--foreground)' }} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 6.75h16.5M3.75 12h16.5m-16.5 5.25h16.5" />
        </svg>
      </button>

      {/* Mobile overlay */}
      {mobileOpen && (
        <div
          className="md:hidden fixed inset-0 z-40 bg-black/40 backdrop-blur-sm"
          onClick={() => setMobileOpen(false)}
        />
      )}

      {/* Mobile sidebar */}
      <nav
        className={`md:hidden fixed inset-y-0 left-0 z-50 w-64 border-r flex flex-col transform transition-transform duration-200 ${
          mobileOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
        style={{
          background: 'var(--card, white)',
          borderColor: 'var(--nav-border)',
        }}
      >
        <div className="flex justify-end p-2">
          <button
            onClick={() => setMobileOpen(false)}
            className="p-2 rounded-lg"
            style={{ color: 'var(--muted)' }}
            aria-label="Close menu"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
        {sidebarContent}
      </nav>

      {/* Desktop sidebar */}
      <nav
        className="hidden md:flex w-60 shrink-0 border-r backdrop-blur flex-col"
        style={{
          background: 'var(--nav-bg)',
          borderColor: 'var(--nav-border)',
        }}
      >
        {sidebarContent}
      </nav>
    </>
  );
}
